/* ============ MEDIA QUERIES ============ */

/* Pantallas pequeñas (móviles pequeños, < 480px) */
@media screen and (max-width: 480px) {
  .fixed.inset-0.z-50 {
    padding: 1rem !important;
    align-items: flex-start !important;
    padding-top: 2rem !important;
  }

  .bg-white\/40.backdrop-blur-2xl {
    padding: 1.5rem !important;
    border-radius: 1.5rem !important;
    gap: 1.5rem !important;
  }

  .w-48.h-48 {
    width: 6rem !important;
    height: 6rem !important;
  }

  h1.text-4xl {
    font-size: 1.75rem !important;
    line-height: 1.2 !important;
  }

  h2.text-lg {
    font-size: 0.875rem !important;
  }

  p.text-lg {
    font-size: 0.9375rem !important;
    line-height: 1.6 !important;
  }

  .flex.flex-wrap.items-center.gap-4 {
    flex-direction: column;
    width: 100%;
  }

  .group.flex.items-center.gap-2 {
    width: 100%;
    justify-content: center;
    padding: 0.75rem 1rem !important;
    font-size: 0.875rem !important;
  }

  .group.relative.inline-flex.items-center.justify-center.px-8.py-4 {
    width: 100%;
  }

  .absolute.top-\[-10\%\] {
    width: 15rem !important;
    height: 15rem !important;
  }

  .absolute.top-\[20\%\].right-\[-5\%\] {
    width: 12rem !important;
    height: 12rem !important;
  }

  .absolute.bottom-\[-10\%\].left-\[20\%\] {
    width: 14rem !important;
    height: 14rem !important;
  }
}

/* Pantallas medianas (tablets, 481px - 768px) */
@media screen and (min-width: 481px) and (max-width: 768px) {
  .fixed.inset-0.z-50 {
    padding: 1.5rem !important;
  }

  .bg-white\/40.backdrop-blur-2xl {
    padding: 2rem !important;
    gap: 2rem !important;
  }

  .w-48.h-48 {
    width: 8rem !important;
    height: 8rem !important;
  }

  h1.text-4xl {
    font-size: 2rem !important;
  }

  p.text-lg {
    font-size: 1rem !important;
  }

  .flex.flex-wrap.items-center.gap-4 {
    justify-content: center;
  }

  .group.flex.items-center.gap-2 {
    padding: 0.625rem 1rem !important;
  }
}

/* Pantallas grandes (escritorio pequeño, 769px - 1024px) */
@media screen and (min-width: 769px) and (max-width: 1024px) {
  .bg-white\/40.backdrop-blur-2xl {
    padding: 2.5rem !important;
    gap: 2.5rem !important;
  }

  .w-48.h-48.md\:w-64.md\:h-64 {
    width: 9rem !important;
    height: 9rem !important;
  }

  h1.text-4xl.md\:text-5xl {
    font-size: 2.25rem !important;
  }
}

/* Pantallas extragrandes (> 1024px) */
@media screen and (min-width: 1025px) {
  .bg-white\/40.backdrop-blur-2xl {
    max-width: 55rem !important;
  }

  h1.text-4xl.md\:text-5xl {
    font-size: 3rem !important;
  }
}

/* Mejoras de rendimiento y accesibilidad */
@media (prefers-reduced-motion: reduce) {
  .animate-blob,
  .animation-delay-2000,
  .animation-delay-4000 {
    animation: none !important;
    transform: none !important;
  }

  .group,
  .group.flex,
  .group.relative {
    transition: none !important;
  }

  .transform,
  .group-hover\:scale-105,
  .hover\:scale-\[1\.02\] {
    transform: none !important;
  }
}

/* Tema oscuro (soporte opcional) */
@media (prefers-color-scheme: dark) {
  .fixed.inset-0.z-50.bg-\[\#F8F4ED\] {
    background: linear-gradient(135deg, #1a1a2e 0%, #16213e 50%, #0f3460 100%) !important;
  }
}

/* Orientación landscape en móviles */
@media screen and (max-width: 768px) and (orientation: landscape) {
  .fixed.inset-0.z-50 {
    align-items: center !important;
    padding-top: 0.5rem !important;
    padding-bottom: 0.5rem !important;
  }

  .bg-white\/40.backdrop-blur-2xl {
    flex-direction: row !important;
    padding: 1rem !important;
    gap: 1rem !important;
    max-height: 90vh !important;
    overflow-y: auto !important;
  }

  .w-48.h-48 {
    width: 5rem !important;
    height: 5rem !important;
    flex-shrink: 0 !important;
  }

  h1.text-4xl {
    font-size: 1.5rem !important;
  }

  h2.text-lg {
    font-size: 0.75rem !important;
  }

  p.text-lg {
    font-size: 0.8125rem !important;
    max-height: 4rem !important;
    overflow: hidden !important;
  }

  .pt-8 {
    padding-top: 0.5rem !important;
    margin-top: 0.5rem !important;
  }

  .absolute {
    display: none !important;
  }
}

/* Impresión */
@media print {
  .fixed.inset-0.z-50 {
    position: relative !important;
    height: auto !important;
    min-height: 100vh !important;
    background: white !important;
  }

  .absolute {
    display: none !important;
  }

  .bg-white\/40.backdrop-blur-2xl {
    background: white !important;
    backdrop-filter: none !important;
    box-shadow: none !important;
    border: 1px solid #ccc !important;
  }

  .group.flex,
  .group.relative {
    display: none !important;
  }
}
